import React, { useState } from 'react';
import IndividualAnalysis from './IndividualAnalysis'; // Assuming this exists
import BatchAnalysis from './BatchAnalysis';
import Dashboard from './Dashboard'; // Assuming this exists
import BatchDashboard from './BatchDashboard';
import './App.css';
import logo from './assets/images/logo.png'; // Assuming this exists

function App() {
  const [customerData, setCustomerData] = useState({
    Tenure: 5,
    OrderCount: 5,
    CashbackAmount: 12000,
    DaySinceLastOrder: 7,
    HourSpendOnApp: 30,
    OrderAmountHikeFromlastYear: 15,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    SatisfactionScore: 3,
    WarehouseToHome: 10,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Single',
    Complain: 0
  });

  const [loading, setLoading] = useState(false);

  const [selectedFile, setSelectedFile] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchLoading, setBatchLoading] = useState(false);

  const [currentView, setCurrentView] = useState('individual');
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [dashboardData, setDashboardData] = useState(null);
  const [batchDashboardData, setBatchDashboardData] = useState(null);

  const handleInputChange = (newData) => {
    setCustomerData(newData);
  };

  const handleAnalysisComplete = (results) => {
    const newDashboardData = {
      individualResult: results,
      timestamp: new Date().toLocaleString(),
      type: 'individual',
      customerData: { ...customerData }
    };
    setDashboardData(newDashboardData);
    setCurrentView('dashboard');
  };

  const handleReset = () => {
    setCustomerData({
      Tenure: 5,
      OrderCount: 5,
      CashbackAmount: 12000,
      DaySinceLastOrder: 7,
      HourSpendOnApp: 30,
      OrderAmountHikeFromlastYear: 15,
      CouponUsed: 1,
      NumberOfDeviceRegistered: 3,
      SatisfactionScore: 3,
      WarehouseToHome: 10,
      NumberOfAddress: 4,
      CityTier: 1,
      PreferredLoginDevice: 'Mobile Phone',
      PreferredPaymentMode: 'Credit Card',
      PreferedOrderCat: 'Laptop & Accessory',
      Gender: 'Male',
      MaritalStatus: 'Single',
      Complain: 0
    });
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setSelectedFile(file);
    // Clear previous results when new file is selected
    setBatchResults(null);
    setBatchDashboardData(null);
  };

  const handleBatchAnalyze = async () => {
    // If no file is selected, we assume the user wants to run the analysis
    // on the backend's internal demo data generator.

    setBatchLoading(true);

    try {
      const formData = new FormData();
      if (selectedFile) {
        formData.append('file', selectedFile);
      }

      console.log('📤 Sending batch analysis request to backend on port 5001...');

      // *** TARGETING DEDICATED BATCH BACKEND ON PORT 5001 ***
      const response = await fetch('http://localhost:5001/api/batch/analyze', {
        method: 'POST',
        // Note: FormData sends the correct multipart/form-data header automatically
        body: selectedFile ? formData : undefined, 
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();

      if (result.success) {
        console.log('✅ Batch analysis successful:', result);

        setBatchResults(result);
        setBatchDashboardData({
          batchResult: result,
          timestamp: new Date().toLocaleString(),
          type: 'batch',
        });
        setCurrentView('batch-dashboard');
      } else {
        console.error('❌ Batch analysis failed:', result.error);
        alert(`Analysis failed: ${result.error}. Message: ${result.message}`);
      }
    } catch (error) {
      console.error('❌ Error during batch analysis:', error);
      alert(`Connection error: ${error.message}. Please ensure the backend server is running on port 5001.`);
    } finally {
      setBatchLoading(false);
    }
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  const navigateToDashboard = () => {
    setCurrentView('dashboard');
  };

  const navigateToBatchDashboard = () => {
    setCurrentView('batch-dashboard');
  };

  return (
    <div className="app">
      <div className="app-header">
        <div className="header-left">
          <div className="logo-title-container">
            <div className="app-logo">
              {/* Placeholder for logo image */}
              <div style={{ width: '40px', height: '40px', background: 'white', borderRadius: '8px' }}></div> 
            </div>
            <div className="title-container">
              <h1 className="app-title">E-commerce ChurnGuard</h1>
            </div>
          </div>
        </div>
        <div className="header-right">
          <div className="header-stats">
            <div className="stat-item">
              <span className="stat-label">Model Accuracy</span>
              <span className="stat-value">92%</span>
            </div>
          </div>
        </div>
      </div>

      <div className="main-layout">
        <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
          <nav className="sidebar-nav">
            <div className="nav-toggle-section">
              <button 
                className="nav-toggle-btn"
                onClick={toggleSidebar}
              >
                <span className="nav-toggle-icon">
                  {sidebarOpen ? '◀' : '▶'}
                </span>
                {sidebarOpen && <span className="nav-toggle-text">Collapse</span>}
                {!sidebarOpen && <span className="nav-toggle-text">Expand</span>}
              </button>
            </div>

            {/* Individual Analysis Section */}
            <div className="nav-section">
              {sidebarOpen && (
                <div className="nav-section-header">
                  <span className="nav-section-title">Individual Analysis</span>
                </div>
              )}
              <button 
                className={`nav-item ${currentView === 'individual' ? 'active' : ''}`}
                onClick={() => setCurrentView('individual')}
                data-tooltip="Individual Analysis"
              >
                <span className="nav-icon">🔍</span>
                {sidebarOpen && <span className="nav-text">Individual Analysis</span>}
              </button>
              <button 
                className={`nav-item ${currentView === 'dashboard' ? 'active' : ''}`}
                onClick={navigateToDashboard}
                data-tooltip="Individual Results"
              >
                <span className="nav-icon">📈</span>
                {sidebarOpen && <span className="nav-text">Individual Results</span>}
              </button>
            </div>

            {/* Batch Processing Section */}
            <div className="nav-section">
              {sidebarOpen && (
                <div className="nav-section-header">
                  <span className="nav-section-title">Batch Processing</span>
                </div>
              )}
              <button 
                className={`nav-item ${currentView === 'batch' ? 'active' : ''}`}
                onClick={() => setCurrentView('batch')}
                data-tooltip="Batch Processing"
              >
                <span className="nav-icon">⚡</span>
                {sidebarOpen && <span className="nav-text">Batch Processing</span>}
              </button>
              <button 
                className={`nav-item ${currentView === 'batch-dashboard' ? 'active' : ''}`}
                onClick={navigateToBatchDashboard}
                data-tooltip="Batch Results"
              >
                <span className="nav-icon">📊</span>
                {sidebarOpen && <span className="nav-text">Batch Results</span>}
              </button>
            </div>
          </nav>
        </div>

        <div className={`content-area ${!sidebarOpen ? 'expanded' : ''}`}>
          {currentView === 'individual' && (
            <>
              <div className="view-title-section">
                <h2 className="view-title">
                  <span className="view-icon">👤</span>
                  Individual Customer Analysis
                </h2>
              </div>
              <IndividualAnalysis
                customerData={customerData}
                onInputChange={handleInputChange}
                onReset={handleReset}
                loading={loading}
                setLoading={setLoading}
                onAnalysisComplete={handleAnalysisComplete}
              />
            </>
          )}

          {currentView === 'batch' && (
            <>
              <div className="view-title-section">
                <h2 className="view-title">
                  <span className="view-icon">⚡</span>
                  Batch Processing
                </h2>
                <p className="view-subtitle">
                  Upload your customer dataset CSV file for batch churn prediction analysis
                </p>
              </div>
              {/* Pass necessary states for file handling and triggering analysis */}
              <BatchAnalysis
                onFileChange={handleFileChange}
                onAnalyze={handleBatchAnalyze}
                loading={batchLoading}
                selectedFile={selectedFile}
                // Removed redundant 'results' prop, dashboard handles display
              />
            </>
          )}

          {currentView === 'dashboard' && (
            <Dashboard dashboardData={dashboardData} />
          )}

          {currentView === 'batch-dashboard' && batchDashboardData && (
            <BatchDashboard dashboardData={batchDashboardData} />
          )}

          {/* Fallback view if navigated directly to batch-dashboard without data */}
          {currentView === 'batch-dashboard' && !batchDashboardData && (
            <div className="view-title-section" style={{padding: '40px', textAlign: 'center', color: '#94a3b8'}}>
                <h2>📊 Batch Analysis Dashboard</h2>
                <p>No batch analysis results available. Please navigate back to 'Batch Processing' (⚡) and run an analysis first.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
